import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class JmmDemo {

    // ── 1. volatile flag — visibility, not atomicity ───────────────
    static volatile boolean running = true;

    static void volatileDemo() throws InterruptedException {
        Thread worker = new Thread(() -> {
            int count = 0;
            while (running) count++;  // sees running=false immediately due to volatile
            System.out.println("Worker stopped at count: " + count);
        });
        worker.start();
        Thread.sleep(10);
        running = false; // visible to worker without volatile: might loop forever
        worker.join();
    }

    // ── 2. AtomicInteger — visibility + atomicity via CAS ──────────
    static AtomicInteger atomicCounter = new AtomicInteger(0);

    static void atomicDemo() throws InterruptedException {
        int threads = 100, iters = 1000;
        ExecutorService pool = Executors.newFixedThreadPool(threads);
        for (int t = 0; t < threads; t++)
            pool.submit(() -> { for (int i = 0; i < iters; i++) atomicCounter.incrementAndGet(); });
        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("AtomicInteger result: " + atomicCounter.get()); // always 100000
    }

    // ── 3. synchronized — compound action ─────────────────────────
    static int unsafeCount = 0;
    static final Object lock = new Object();

    static void synchronizedDemo() throws InterruptedException {
        int threads = 100, iters = 1000;
        ExecutorService pool = Executors.newFixedThreadPool(threads);
        for (int t = 0; t < threads; t++)
            pool.submit(() -> {
                for (int i = 0; i < iters; i++) {
                    synchronized (lock) { unsafeCount++; }  // now safe
                }
            });
        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("Synchronized result: " + unsafeCount); // always 100000
    }

    // ── 4. ThreadLocal — per-thread data ──────────────────────────
    static ThreadLocal<String> requestId = ThreadLocal.withInitial(() -> "none");

    static void threadLocalDemo() throws InterruptedException {
        Thread t1 = new Thread(() -> {
            requestId.set("req-001");
            System.out.println(Thread.currentThread().getName() + ": " + requestId.get());
        }, "thread-1");
        Thread t2 = new Thread(() -> {
            requestId.set("req-002");
            System.out.println(Thread.currentThread().getName() + ": " + requestId.get());
        }, "thread-2");
        t1.start(); t2.start();
        t1.join(); t2.join();
        // Each thread sees its own value; main thread still sees "none"
        System.out.println("Main: " + requestId.get());
    }

    public static void main(String[] args) throws InterruptedException {
        volatileDemo();
        atomicDemo();
        synchronizedDemo();
        threadLocalDemo();
    }
}

