import java.util.concurrent.atomic.*;
import java.util.*;

public class Q2 {
    static class Node {
        int val; Node next;
        Node(int val, Node next) { this.val = val; this.next = next; }
    }

    static AtomicReference<Node> head = new AtomicReference<>(null);

    static void push(int val) {
        Node newNode, current;
        do {
            current = head.get();
            newNode = new Node(val, current);
        } while (!head.compareAndSet(current, newNode));
    }

    static int pop() {
        Node current, next;
        do {
            current = head.get();
            if (current == null) return -1;
            next = current.next;
        } while (!head.compareAndSet(current, next));
        return current.val;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;
            if (line.startsWith("PUSH")) push(Integer.parseInt(line.split(" ")[1]));
            else System.out.println(pop());
        }
    }
}

