import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Q3 {
    static volatile boolean stopped = false;
    static LinkedBlockingQueue<Integer> queue = new LinkedBlockingQueue<>();
    static AtomicInteger produced = new AtomicInteger(0);
    static AtomicInteger consumed = new AtomicInteger(0);

    public static void main(String[] args) throws InterruptedException {
        Thread producer = new Thread(() -> {
            int n = 1;
            while (!stopped) {
                queue.offer(n++);
                produced.incrementAndGet();
            }
        });
        Thread consumer = new Thread(() -> {
            while (!stopped || !queue.isEmpty()) {
                Integer val = queue.poll();
                if (val != null) consumed.incrementAndGet();
            }
        });
        producer.start();
        consumer.start();
        Thread.sleep(100);
        stopped = true;
        producer.join();
        consumer.join();
        System.out.println("Produced: " + produced.get());
        System.out.println("Consumed: " + consumed.get());
    }
}
